changeSet.sql:
CREATE TABLE IF NOT EXISTS audit_log (
    id          BIGSERIAL PRIMARY KEY,
    actor_id    BIGINT NOT NULL REFERENCES "user"(id) ON DELETE CASCADE,
    method      VARCHAR(7) NOT NULL,
    path        VARCHAR(512) NOT NULL,
    status_code SMALLINT NOT NULL,
    request_body JSONB,
    ip_address  VARCHAR(45) NOT NULL,
    created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX idx_audit_log_created_at ON audit_log (created_at);
CREATE INDEX idx_audit_log_actor_id ON audit_log (actor_id);

COMMENT ON TABLE audit_log IS 'Stores audit log entries for admin actions';
COMMENT ON COLUMN audit_log.id IS 'Unique identifier for the audit log entry';
COMMENT ON COLUMN audit_log.actor_id IS 'Reference to the user who performed the action';
COMMENT ON COLUMN audit_log.method IS 'HTTP method of the request (GET, POST, PUT, PATCH, DELETE, etc.)';
COMMENT ON COLUMN audit_log.path IS 'Request path, truncated to 512 characters';
COMMENT ON COLUMN audit_log.status_code IS 'HTTP response status code';
COMMENT ON COLUMN audit_log.request_body IS 'Request body as JSONB, null for GET/HEAD/OPTIONS';
COMMENT ON COLUMN audit_log.ip_address IS 'Client IP address (IPv4 or IPv6)';
COMMENT ON COLUMN audit_log.created_at IS 'Timestamp when the audit log entry was created';
COMMENT ON INDEX idx_audit_log_created_at IS 'Index for querying audit logs by creation time';
COMMENT ON INDEX idx_audit_log_actor_id IS 'Index for querying audit logs by actor';
